  2→
  3→data class IntegrationSnippetsResponse(
  4→    val keycloakUrl: String,
  5→    val realmName: String,
  6→    val clientId: String,
  7→    val isPublicClient: Boolean,
  8→    val snippets: IntegrationSnippets? = null,
