 11→
 12→data class IntegrationSnippets(
 13→    val vanillaJs: String,
 14→    val react: String,
 15→    val vue: String
 16→)
 17→
 18→data class BackendIntegrationSnippets(
 19→    val applicationYml: String,
 20→    val securityConfig: String,
 21→    val authClient: String,
 22→    val buildGradle: String
 23→)
 24→
 25→object IntegrationSnippetGenerator {
 26→
 27→    fun generateFrontend(keycloakUrl: String, realmName: String, clientId: String): IntegrationSnippets {
 28→        return IntegrationSnippets(
 29→            vanillaJs = generateVanillaJs(keycloakUrl, realmName, clientId),
 30→            react = generateReact(keycloakUrl, realmName, clientId),
 31→            vue = generateVue(keycloakUrl, realmName, clientId)
 32→        )
 33→    }
 34→
 35→    fun generateBackend(keycloakUrl: String, realmName: String, clientId: String, authBackendUrl: String): BackendIntegrationSnippets {
 36→        return BackendIntegrationSnippets(
 37→            applicationYml = generateApplicationYml(keycloakUrl, realmName, clientId),
 38→            securityConfig = generateSecurityConfig(keycloakUrl, realmName),
 39→            authClient = generateAuthClient(authBackendUrl, clientId),
 40→            buildGradle = generateBuildGradle()
 41→        )
 42→    }
 43→
 44→    private fun generateVanillaJs(keycloakUrl: String, realmName: String, clientId: String): String {
 45→        return """
 46→import Keycloak from "keycloak-js";
 47→
 48→const keycloak = new Keycloak({
 49→  url: "$keycloakUrl",
 50→  realm: "$realmName",
 51→  clientId: "$clientId"
 52→});
 53→
 54→// Initialize Keycloak
 55→keycloak.init({
 56→  onLoad: "login-required",
 57→  checkLoginIframe: false,
 58→  pkceMethod: "S256"
 59→}).then(authenticated => {
 60→  if (authenticated) {
 61→    console.log("User authenticated");
 62→    console.log("Token:", keycloak.token);
 63→
 64→    // Access user info
 65→    keycloak.loadUserProfile().then(profile => {
 66→      console.log("User:", profile.email);
 67→    });
 68→  }
 69→}).catch(error => {
 70→  console.error("Authentication failed:", error);
 71→});
 72→
 73→// Token refresh
 74→keycloak.onTokenExpired = () => {
 75→  keycloak.updateToken(30).catch(() => {
 76→    console.log("Token refresh failed, re-authenticating...");
 77→    keycloak.login();
 78→  });
 79→};
 80→
 81→// Use token in API calls
 82→async function fetchWithAuth(url, options = {}) {
 83→  await keycloak.updateToken(30);
 84→  return fetch(url, {
 85→    ...options,
 86→    headers: {
 87→      ...options.headers,
 88→      Authorization: `Bearer ${'$'}{keycloak.token}`
 89→    }
 90→  });
 91→}
 92→        """.trimIndent()
 93→    }
 94→
 95→    private fun generateReact(keycloakUrl: String, realmName: String, clientId: String): String {
 96→        return """
 97→// useKeycloak.ts
 98→import { useState, useEffect, useCallback } from "react";
 99→import Keycloak from "keycloak-js";
100→
101→const keycloakConfig = {
102→  url: "$keycloakUrl",
103→  realm: "$realmName",
104→  clientId: "$clientId"
105→};
106→
107→const keycloak = new Keycloak(keycloakConfig);
108→
109→export function useKeycloak() {
110→  const [authenticated, setAuthenticated] = useState(false);
111→  const [loading, setLoading] = useState(true);
112→  const [token, setToken] = useState<string | undefined>();
113→  const [user, setUser] = useState<any>(null);
114→
115→  useEffect(() => {
116→    keycloak.init({
117→      onLoad: "login-required",
118→      checkLoginIframe: false,
119→      pkceMethod: "S256"
120→    }).then(auth => {
121→      setAuthenticated(auth);
122→      setToken(keycloak.token);
123→      if (auth) {
124→        keycloak.loadUserProfile().then(setUser);
125→      }
126→    }).finally(() => {
127→      setLoading(false);
128→    });
129→
130→    keycloak.onTokenExpired = () => {
131→      keycloak.updateToken(30).then(refreshed => {
132→        if (refreshed) setToken(keycloak.token);
133→      });
134→    };
135→  }, []);
136→
137→  const login = useCallback(() => keycloak.login(), []);
138→  const logout = useCallback(() => keycloak.logout(), []);
139→
140→  const fetchWithAuth = useCallback(async (url: string, options: RequestInit = {}) => {
141→    await keycloak.updateToken(30);
142→    return fetch(url, {
143→      ...options,
144→      headers: {
145→        ...options.headers,
146→        Authorization: `Bearer ${'$'}{keycloak.token}`
147→      }
148→    });
149→  }, []);
150→
151→  return { authenticated, loading, token, user, login, logout, fetchWithAuth };
152→}
153→
154→// Usage in component:
155→// const { authenticated, user, fetchWithAuth } = useKeycloak();
156→        """.trimIndent()
157→    }
158→
159→    private fun generateVue(keycloakUrl: String, realmName: String, clientId: String): String {
160→        return """
161→// keycloak.ts
162→import Keycloak from "keycloak-js";
163→import { ref, readonly } from "vue";
164→import type { App } from "vue";
165→
166→const keycloakConfig = {
167→  url: "$keycloakUrl",
168→  realm: "$realmName",
169→  clientId: "$clientId"
170→};
171→
172→const keycloak = new Keycloak(keycloakConfig);
173→const authenticated = ref(false);
174→const loading = ref(true);
175→const token = ref<string>();
176→const user = ref<any>(null);
177→
178→export const useKeycloak = () => ({
179→  keycloak,
180→  authenticated: readonly(authenticated),
181→  loading: readonly(loading),
