263→    private fun generateSecurityConfig(keycloakUrl: String, realmName: String): String {
264→        return """
265→package com.example.config
266→
267→import org.springframework.context.annotation.Bean
268→import org.springframework.context.annotation.Configuration
269→import org.springframework.security.config.annotation.web.builders.HttpSecurity
270→import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity
271→import org.springframework.security.config.http.SessionCreationPolicy
272→import org.springframework.security.oauth2.server.resource.authentication.JwtAuthenticationConverter
273→import org.springframework.security.oauth2.server.resource.authentication.JwtGrantedAuthoritiesConverter
274→import org.springframework.security.web.SecurityFilterChain
275→
276→@Configuration
277→@EnableWebSecurity
278→class SecurityConfig {
279→
280→    @Bean
281→    fun securityFilterChain(http: HttpSecurity): SecurityFilterChain {
282→        return http
283→            .csrf { it.disable() }
284→            .sessionManagement { it.sessionCreationPolicy(SessionCreationPolicy.STATELESS) }
285→            .authorizeHttpRequests { auth ->
286→                auth
287→                    .requestMatchers("/api/public/**").permitAll()
288→                    .requestMatchers("/actuator/health").permitAll()
289→                    .anyRequest().authenticated()
290→            }
291→            .oauth2ResourceServer { oauth2 ->
292→                oauth2.jwt { jwt ->
293→                    jwt.jwtAuthenticationConverter(jwtAuthenticationConverter())
294→                }
295→            }
296→            .build()
297→    }
298→
299→    @Bean
300→    fun jwtAuthenticationConverter(): JwtAuthenticationConverter {
301→        val grantedAuthoritiesConverter = JwtGrantedAuthoritiesConverter()
302→        // Extract roles from Keycloak's realm_access.roles claim
303→        grantedAuthoritiesConverter.setAuthoritiesClaimName("realm_access")
304→        grantedAuthoritiesConverter.setAuthorityPrefix("ROLE_")
305→
306→        val converter = JwtAuthenticationConverter()
307→        converter.setJwtGrantedAuthoritiesConverter { jwt ->
308→            // Custom role extraction from Keycloak token
309→            @Suppress("UNCHECKED_CAST")
310→            val realmAccess = jwt.getClaim<Map<String, Any>>("realm_access")
311→            val roles = (realmAccess?.get("roles") as? List<String>) ?: emptyList()
312→            roles.map { org.springframework.security.core.authority.SimpleGrantedAuthority("ROLE_${'$'}it") }
313→        }
314→        return converter
315→    }
316→}
317→        """.trimIndent()
318→    }
