320→    private fun generateAuthClient(authBackendUrl: String, clientId: String): String {
321→        return """
322→package com.example.client
323→
324→import org.springframework.beans.factory.annotation.Value
325→import org.springframework.http.MediaType
326→import org.springframework.stereotype.Component
327→import org.springframework.web.reactive.function.client.WebClient
328→import java.util.UUID
329→
330→/**
331→ * Client for communicating with the auth backend to manage authorized users.
332→ * Uses client credentials flow for authentication.
333→ */
334→@Component
335→class AuthBackendClient(
336→    @Value("${'$'}{auth.backend.url}") private val authBackendUrl: String,
337→    private val webClientBuilder: WebClient.Builder
338→) {
339→    private val webClient = webClientBuilder
340→        .baseUrl(authBackendUrl)
341→        .build()
342→
343→    /**
344→     * Add users to the authorized list for this client.
345→     * These users will be able to log in via Keycloak.
346→     */
347→    suspend fun addAuthorizedUsers(clientUuid: UUID, users: List<UserRef>, token: String): AddUsersResponse {
348→        return webClient.post()
349→            .uri("/api/clients/{clientId}/users", clientUuid)
350→            .header("Authorization", "Bearer ${'$'}token")
351→            .contentType(MediaType.APPLICATION_JSON)
352→            .bodyValue(AddUsersRequest(users))
353→            .retrieve()
354→            .bodyToMono(AddUsersResponse::class.java)
355→            .block()!!
356→    }
357→
358→    /**
359→     * Remove users from the authorized list.
360→     */
361→    suspend fun removeAuthorizedUsers(clientUuid: UUID, emails: List<String>, token: String): RemoveUsersResponse {
362→        return webClient.method(org.springframework.http.HttpMethod.DELETE)
363→            .uri("/api/clients/{clientId}/users", clientUuid)
364→            .header("Authorization", "Bearer ${'$'}token")
365→            .contentType(MediaType.APPLICATION_JSON)
366→            .bodyValue(RemoveUsersRequest(emails))
367→            .retrieve()
368→            .bodyToMono(RemoveUsersResponse::class.java)
369→            .block()!!
370→    }
371→
372→    /**
373→     * Check if a user is authorized for this client.
374→     */
375→    suspend fun isUserAuthorized(clientUuid: UUID, email: String, token: String): Boolean {
376→        return webClient.get()
377→            .uri("/api/clients/{clientId}/users/{email}/authorized", clientUuid, email)
378→            .header("Authorization", "Bearer ${'$'}token")
379→            .retrieve()
380→            .bodyToMono(AuthorizationCheckResponse::class.java)
381→            .map { it.authorized }
382→            .block() ?: false
383→    }
384→}
385→
386→data class UserRef(val email: String, val keycloakId: String? = null)
387→data class AddUsersRequest(val users: List<UserRef>)
388→data class RemoveUsersRequest(val emails: List<String>)
389→data class AddUsersResponse(val added: List<String>, val alreadyExists: List<String>, val failed: List<String>)
390→data class RemoveUsersResponse(val removed: List<String>, val notFound: List<String>)
391→data class AuthorizationCheckResponse(val authorized: Boolean, val email: String, val clientId: String)
392→        """.trimIndent()
393→    }
